function solve(nums) {
    let totalCost = 0;
    const n = nums.length;

    if (n <= 1) {
        return 0;
    }

    // The minimum total sum of x's required is the sum of all positive differences 
    // nums[i] - nums[i+1]. This represents the minimum cumulative increase 
    // needed at each step to ensure the non-decreasing property is met, 
    // where the total cost equals the sum of all positive increments in the required increase profile C.

    for (let i = 0; i < n - 1; i++) {
        const difference = nums[i] - nums[i+1];

        if (difference > 0) {
            totalCost += difference;
        }
    }

    return totalCost;
}

